export class AuthClient {
  private tokens: TokenPair | null = null;
  private baseUrl: string;
  private refreshBuffer: number;

  constructor(baseUrl: string, refreshBufferSeconds = 60) {
    this.baseUrl = baseUrl;
    this.refreshBuffer = refreshBufferSeconds;
  }

  async login(username: string, password: string): Promise<void> {
    const resp = await fetch(`${this.baseUrl}/auth/login`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ username, password }),
    });
    if (!resp.ok) throw new Error('Login failed');
    this.tokens = await resp.json();
  }

  private isExpiringSoon(): boolean {
    if (!this.tokens) return false;
    const now = Math.floor(Date.now() / 1000);
    return now >= this.tokens.expiresAt - this.refreshBuffer;
  }

  private async refreshTokens(): Promise<void> {
    if (!this.tokens) throw new Error('No tokens to refresh');
    const resp = await fetch(`${this.baseUrl}/auth/refresh`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ refreshToken: this.tokens.refreshToken }),
    });
    if (!resp.ok) throw new Error('Token refresh failed');
    this.tokens = await resp.json();
  }

  async getValidToken(): Promise<string> {
    if (!this.tokens) throw new Error('Not authenticated');
    if (this.isExpiringSoon()) {
      await this.refreshTokens();
    }
    return this.tokens.accessToken;
  }

  getAccessToken(): string | null {
    return this.tokens?.accessToken ?? null;
  }
}
